public class Solution { public List<List<string>> GroupAnagrams(string[] strs) { Dictionary<string, List<string>> dict = new Dictionary<string, List<string>>(); for (int i = 0; i < strs.Length; i++) { int[] array = new int[26]; foreach (char c in strs[i]) { int ic = (int)c - 97; array[ic]++; } string arrayKey = String.Join(",", array); if (!dict.ContainsKey(arrayKey)) { dict.Add(arrayKey, new List<string>() { strs[i] }); } else { dict[arrayKey].Add(strs[i]); } } return dict.Values.ToList(); } }
